import type { Props, HookReturn } from '/virtual/types';
import * as constants from '/virtual/constants';
// hooks.ts — state, handlers, data transformations
import { useState, useEffect, useMemo, useCallback, useRef } from 'react';

export function useComponent(props: Props): HookReturn {
  const { elements } = props;

  const [searchQuery, setSearchQuery] = useState('');
  const [selectedElement, setSelectedElement] = useState<HookReturn['selectedElement']>(null);

  const filteredElements = useMemo(() => {
    const lowerQuery = searchQuery.toLowerCase();
    return elements.filter(
      (el) =>
        el.name.toLowerCase().includes(lowerQuery) ||
        el.symbol.toLowerCase().includes(lowerQuery)
    );
  }, [elements, searchQuery]);

  const categories = useMemo(() => {
    return Array.from(new Set(elements.map((el) => el.category)));
  }, [elements]);

  const handleElementClick = useCallback((element: HookReturn['selectedElement']) => {
    setSelectedElement(element);
  }, []);

  return {
    searchQuery,
    setSearchQuery,
    filteredElements,
    selectedElement,
    handleElementClick,
    categories,
  };
}


