import { ProfileData } from '/virtual/types';

export const EMAIL_REGEX = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;

export const ROLE_OPTIONS = ['Developer', 'Designer', 'Manager', 'Other'];
export const AVATAR_OPTIONS = ['👤', '🚀', '🎨', '💼'];

export const DEFAULT_PROFILE_DATA: ProfileData = {
  name: '',
  email: '',
  avatar: AVATAR_OPTIONS[0],
  role: ROLE_OPTIONS[0],
  emailNotifications: true,
  theme: 'light',
};

export const TOTAL_STEPS = 3;

// --- hooks.ts ---
// Path: /virtual/hooks.ts
import type { Props, HookReturn } from '/virtual/types';
import * as constants from '/virtual/constants';
// hooks.ts — state, handlers, data transformations
import { useState, useEffect, useMemo, useCallback, useRef } from 'react';

export function useComponent(props: OnboardingWizardProps): HookReturn {
  const [currentStep, setCurrentStep] = useState(0);
  const [profile, setProfile] = useState<ProfileData>(() => ({
    name: '',
    email: '',
    avatar: '',
    role: 'Developer',
    emailNotifications: false,
    theme: 'light',
    ...props.initialProfile,
  }));

  const validateStep = useCallback((step: number) => {
    if (step === 0) {
      const emailRegex = /^\S+@\S+\.\S+$/;
      return !(profile.name && emailRegex.test(profile.email) && profile.avatar);
    }
    return false;
  }, [profile]);

  const isNextDisabled = useMemo(() => validateStep(currentStep), [currentStep, validateStep]);

  const handleNext = () => {
    if (!isNextDisabled && currentStep < 2) {
      setCurrentStep((s) => s + 1);
    }
  };

  const handleBack = () => {
    if (currentStep > 0) setCurrentStep((s) => s - 1);
  };

  const updateField = <K extends keyof ProfileData>(field: K, value: ProfileData[K]) => {
    setProfile((prev) => ({ ...prev, [field]: value }));
  };

  const submit = () => props.onComplete(profile);

  return {
    currentStep,
    profile,
    isNextDisabled,
    handleNext,
    handleBack,
    updateField,
    submit,
  };
}


