import type { Props, HookReturn } from '/virtual/types';
// components/index.tsx — main component composing sub-components
import React from 'react';
import { Container, Card, Stack, Box, Text, Heading, Button, Progress } from '@ggui-ai/design/primitives';

export function MainView(props: HookReturn) {
  const { currentStep, profile, isNextDisabled, handleNext, handleBack, updateField, submit } = props;

  return (
    <Container maxWidth="sm" padding={24}>
      <Card shadow="md" padding={32} radius="lg">
        <Stack gap={16}>
          <Heading level={3}>Welcome to Onboarding</Heading>
          <StepIndicator currentStep={currentStep} totalSteps={3} />
          <Progress value={currentStep} max={3} />
        </Stack>
        <Box paddingY={32} style={{ minHeight: '300px' }}>
          {currentStep === 1 && (
            <ProfileForm data={profile} onChange={updateField} />
          )}
          {currentStep === 2 && (
            <PreferencesForm data={profile} onChange={updateField} />
          )}
          {currentStep === 3 && (
            <ReviewSection data={profile} />
          )}
        </Box>
        <Stack direction="horizontal" justify="between" align="center" gap={16}>
          {currentStep > 1 ? (
            <Button variant="ghost" onClick={handleBack}>Back</Button>
          ) : <div />}
          {currentStep < 3 ? (
            <Button variant="primary" onClick={handleNext} disabled={isNextDisabled}>
              Next
            </Button>
          ) : (
            <Button variant="primary" onClick={submit}>Complete Setup</Button>
          )}
        </Stack>
      </Card>
    </Container>
  );
}


